import logging
from azure.functions import HttpRequest, HttpResponse
from azure.storage.blob import BlobServiceClient

def main(req: HttpRequest) -> HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Retrieve the blob path from query parameters
    blob_path = req.params.get('blobPath')
    
    if not blob_path:
        return HttpResponse("Please pass a blobPath on the query string", status_code=400)

    try:
        # Azure Storage connection string and container name
        connection_string = "your_connection_string"
        container_name = "your_container_name"

        # Create a BlobServiceClient object which will be used to create a container client
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container_name)

        # Get the blob client using the blob path
        blob_client = container_client.get_blob_client(blob_path)

        # Download the blob content
        download_stream = blob_client.download_blob()
        file_content = download_stream.readall()

        return HttpResponse(file_content, status_code=200)
    except Exception as e:
        logging.error(f"Error reading blob: {e}")
        return HttpResponse("Error reading the blob", status_code=500)